const r={name:"Aronia",icon:"aronia",category:"bär",family:"Rosväxter",familyLatin:"Rosaceae",perennial:!0,lifespan:"20-30+ år",difficulty:"Enkel",difficultyWhy:"Aronia är en av de mest lättskötta bärbuskarna som finns. Extremt härdig, tål all svensk vinter, angrips sällan av skadedjur och ger pålitlig skörd år efter år. Enda nackdelen? Bären är ganska sträva att äta färska - men processade är de fantastiska.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:null,greenhouse:null},days:"Skörd år 2-3, full skörd år 4-5",spacing:"100-150 cm",rowSpacing:"250-300 cm",depth:"Något djupare än i krukan",depthNote:"Plantera 3-5 cm djupare än busken stod i krukan - det stimulerar nya basalskott.",ph:{min:5,max:7,ideal:6},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Aronia ger bäst skörd i full sol men klarar halvskugga förvånansvärt bra. I skuggigare lägen blir bären färre men höstfärgen blir nästan ännu mer spektakulär. Minst 4-5 timmar sol per dag för ordentlig bärsättning."},temperature:{min:-35,max:35,ideal:"15-25°C",detail:"En av de härdigaste bärbuskarna - tål ner till -35°C utan vinterskydd. Ursprungligen från Nordamerikas kalla regioner och anpassad till skandinaviskt klimat. Klarar alla svenska odlingszoner utan problem."},wind:{level:"Tålig",detail:"Kompakt, stabil buske som klarar vind bra. Har inga långa rankande skott som kan knäckas. Fungerar faktiskt utmärkt som vindskyddshäck."}},watering:{need:"Låg-Medel",icon:"water",summary:"Aronia är anspråkslös och torktålig när den väl etablerats. Under de första åren behöver hon regelbunden vattning, men en etablerad buske klarar sig med minimal hjälp de flesta svenska somrar.",phases:[{phase:"Etablering (år 1-2)",need:"Medel",tip:"Vattna regelbundet första och andra sommaren. Busken bygger upp sitt rotsystem och behöver jämn fukt för att komma igång ordentligt."},{phase:"Blomning (maj-juni)",need:"Medel",tip:"Jämn fukt under blomningen ger bättre fruktsättning. Aronia är delvis självfertil men pollinatörer hjälper - vattenstress kan minska pollineringsviljan."},{phase:"Bärmognad (juli-aug)",need:"Låg-Medel",tip:"Etablerade buskar klarar sig oftast själva. Vid extrem torka (2+ veckor utan regn) ger en djup vattning större och saftigare bär."},{phase:"Höst/vinter",need:"Låg",tip:"Minska vattningen. Busken klarar sig själv och förbereder sin spektakulära höstfärg."}],mistakes:["Vattnar för mycket - aronia avskyr vattensjuk jord","Glömmer nyplanterade buskar de första somrarna - de behöver hjälp att etablera sig","Övervattnar i tung lerjord utan dränering"],tip:"Mulcha med bark eller gräsklipp runt busken - det håller fukten jämn och minskar ogräs. En etablerad aronia med bra mulch klarar sig nästan helt utan extra vattning."},soil:"Aronia trivs i de flesta jordtyper och är remarkabelt anpassningsbar. Hon föredrar fukthållande, humusrik jord men klarar allt från sandjord till lerjord. Undvik bara extremt vattensjuk mark.",soilTips:["Blanda in kompost vid plantering - aronia uppskattar en näringsrik start","Klarar lerjord bättre än de flesta bärbuskar - bara dräneringen är okej","Sandjord? Blanda in kompost och mulcha rikligt för att hålla fukten","Tolererar ett brett pH-spann (5.0-7.0) - funkar i de flesta svenska trädgårdar utan justering","Mulcha årligen med bark eller gräsklipp"],timeline:{1:[{phase:"Plantering",months:"Okt-nov eller april-maj",icon:"seedling"},{phase:"Blomning",months:"Maj-juni",icon:"bloom"},{phase:"Skörd",months:"Aug-sept",icon:"harvest"},{phase:"Beskärning",months:"Tidig vår (mars)",icon:"scissors"},{phase:"Höstfärg",months:"Sept-okt",icon:"bloom"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],4:[{phase:"Plantering",months:"Okt eller april-maj",icon:"seedling"},{phase:"Blomning",months:"Maj",icon:"bloom"},{phase:"Skörd",months:"Aug-sept",icon:"harvest"},{phase:"Beskärning",months:"Tidig vår (feb-mars)",icon:"scissors"},{phase:"Höstfärg",months:"Sept-okt",icon:"bloom"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],6:[{phase:"Plantering",months:"Okt-nov eller mars-april",icon:"seedling"},{phase:"Blomning",months:"Maj",icon:"bloom"},{phase:"Skörd",months:"Aug",icon:"harvest"},{phase:"Beskärning",months:"Sen vinter (feb-mars)",icon:"scissors"},{phase:"Höstfärg",months:"Okt",icon:"bloom"},{phase:"Vintervila",months:"Nov-feb",icon:"snowflake"}]},nutritionData:[{month:"Apr",N:3,P:2,K:2},{month:"Maj",N:4,P:3,K:3},{month:"Jun",N:3,P:4,K:4},{month:"Jul",N:2,P:3,K:5},{month:"Aug",N:2,P:2,K:4},{month:"Sep",N:1,P:1,K:2}],nutritionTips:[{timing:"Tidig vår (mars-april)",tip:"Ge en giva kompost eller brunnen gödsel runt busken. Aronia är inte speciellt hungrig men uppskattar en vårstart med näring."},{timing:"Blomning (maj)",tip:"En giva kaliumrik gödsel stärker blomning och bärkvalitet. Vedaska fungerar utmärkt och är gratis."},{timing:"Höst",tip:"Lägg ett lager kompost som höstmulch. Det bryts ner under vintern och matar busken lagom till vårstarten."}],companions:{good:[{id:"ringblomma",name:"Ringblomma",icon:"flower",why:"Lockar pollinatörer som förbättrar bärsättningen. Aronia gynnas av korspollinering trots att hon är delvis självfertil."},{name:"Andra aroniasorter",icon:"berry",why:"Korspollinering mellan olika sorter ger betydligt bättre skörd och större bär. Plantera gärna Viking och Hugin tillsammans."},{id:"graslok",name:"Gräslök",icon:"herb",why:"Doften avskräcker bladlöss. Tidig blomning lockar pollinatörer. Fint marktäckande under buskarna."}],bad:[{id:"potatis",name:"Potatis",icon:"vegetable",why:"Risk för delad verticillium-svamp. Håll bra avstånd."}]},rotation:{avoid:[{name:"Aronia"},{name:"Andra Rosaceae (äpple, päron, hallon)"}],avoidWhy:"Rosväxter kan dela svampsjukdomar. Plantera inte ny aronia där gammal stått - vänta minst 4-5 år.",goodBefore:[{name:"Solig, öppen plats"},{name:"Gräsmatta"}],goodBeforeWhy:"En plats som inte odlats med rosväxter nyligen. Gräsmattejord är ofta perfekt - frisk och ogödslad.",goodAfter:[{name:"Gröngödsling"},{name:"Baljväxter"}],goodAfterWhy:"Efter 20+ år med aronia kan jorden behöva förnyelse. Gröngödsling eller baljväxter bygger upp den."},varieties:[{name:"Viking",zones:[1,2,3,4,5],note:"Den vanligaste sorten i Sverige och Norden. Stora bär i rikliga klasar. Upprätt, kraftig buske (1.5-2 m). Pålitlig och lättskörd. Ryskt ursprung (Mitchurin), namngiven i Finland."},{name:"Hugin",zones:[1,2,3,4,5],note:"E-planta! Utvald vid SLU Alnarp från vilt material från Kanada. Kompaktare buske (1-1.5 m), perfekt för mindre trädgårdar. Stora bär och fin höstfärg. Rekommenderas varmt."},{name:"Nero",zones:[1,2,3,4,5],note:"Ryskt ursprung (Mitchurin), spridd via Östeuropa. Extra stora bär. Något lägre buske (1-1.5 m). Hög bärproduktion och mild smak jämfört med Viking. Populär i kommersiell odling."},{name:"Aron",zones:[1,2,3,4,5,6],note:"Populär i dansk odling. Kompakt växtsätt. Stora, fasta bär. Bra val för häck eller begränsade utrymmen. Fin höstfärg."}],problems:[{name:"Fåglar",symptom:"Bären försvinner innan du hinner skörda. Trastar och starar är de vanligaste bovarna.",fix:"Nät är det enda pålitliga skyddet. Sätt upp nät när bären börjar färgas (juli-aug). Aronia ger rikligt - det finns oftast gott om bär till alla om du har flera buskar."},{name:"Mjöldagg",symptom:"Vitt, mjöligt belägg på bladen, främst i slutet av säsongen. Vanligare i fuktiga, varma somrar.",fix:"God luftcirkulation genom gallring. Aronia drabbas lindrigare än många andra Rosaceae. Sällan allvarligt - busken klarar sig bra ändå."},{name:"Bladfläcksjuka",symptom:"Bruna eller mörkröda fläckar på bladen. Kan orsaka tidigt bladfall vid kraftigt angrepp.",fix:"Rensa bort nedfallna löv som kan sprida smitta. God luftcirkulation. Aronia är generellt motståndskraftig - problemet är sällan allvarligt."}],goodToKnow:[{icon:"tip",title:"Antioxidant-bomben",text:"Aroniabär har bland de allra högsta antioxidantnivåerna av alla bär - högre än blåbär, acai och granatäpple. De mörka bären är fullpackade med antocyaniner. Ät dem processade (juice, sylt, torkade) för bäst effekt.",severity:"tip"},{icon:"warning",title:"Sträva färska",text:"Aroniabär smakar intensivt sträva/adstringerande färska - munnen drar ihop sig. Det är helt normalt och beror på de höga tanninerna. Processa dem istället: juice, sylt, torkade eller i smoothies. Smaken förvandlas helt!",severity:"warning"},{icon:"tip",title:"Spektakulär höstfärg",text:"Aronia har en av trädgårdens absolut vackraste höstfärger. Bladen exploderar i eldröda, orange och karmosinröda toner i september-oktober. Plantera henne synligt - hon är minst lika mycket prydnadsbuske som nyttobuske.",severity:"tip"},{icon:"tip",title:"Perfekt häckväxt",text:"Aronia fungerar fantastiskt som friväxande häck. Kompakt växtsätt, vacker blomning på våren, bär på sommaren och eldröd höstfärg. Dessutom extremt härdig och lättskött. Vad mer kan man be om?",severity:"tip"},{icon:"tip",title:"Nästan inga skadedjur",text:"Aronia är ovanligt resistent mot sjukdomar och skadedjur. De sträva bären verkar avskräcka de flesta insekter. Fåglar är det enda riktiga hotet - och det löser du med nät.",severity:"tip"},{icon:"warning",title:"Rotskott kan sprida sig",text:"Aronia bildar rotskott, men inte lika aggressivt som hallon eller havtorn. Håll koll och klipp bort oönskade skott. I en häck är det en fördel - busken fyller ut naturligt.",severity:"warning"}],sowing:{method:"direct",label:"Plantering",description:"Aronia planteras som barrotade buskar (höst eller tidig vår) eller krukodlade plantor. Höstplantering ger bäst etablering. Busken är anspråkslös och ställer inga konstiga krav.",steps:["Gräv en grop dubbelt så bred som rotklumpen och lika djup plus 5 cm","Blanda in kompost i jorden - aronia uppskattar en näringsrik start","Plantera 3-5 cm djupare än busken stod i krukan","Vattna rikligt - riktigt genomblött","Mulcha med bark eller gräsklipp runt busken (inte intill stammen)","Klipp ner till 20-30 cm vid plantering för att stimulera nya basalskott"],tips:["Höstplantering (okt-nov) ger bäst resultat - rötterna etablerar sig i fred","Plantera gärna 2+ sorter för bättre korspollinering och större skörd","Fungerar utmärkt som häck med 80-100 cm avstånd","Första ordentliga skörden kommer år 3, full skörd från år 4-5"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Vegetativ förökning",biennial:!1,description:"Aronia förökas enkelt med rotskott, sticklingar eller delning. Busken bildar naturligt rotskott som kan grävas upp och planteras om. Frösådd fungerar men ger viss variation.",steps:["Rotskott (enklast): gräv försiktigt upp rotskott med egna rötter på hösten","Plantera om rotskottet direkt på sin nya plats eller i kruka","Vedartade sticklingar: klipp 15-20 cm bitar av årets mogna ved i november","Sätt sticklingarna i fuktig jord utomhus med 2-3 knoppar ovan mark","Delning: gräv upp en etablerad buske och dela med spade. Plantera om delarna direkt."],isolation:"Vegetativ förökning ger exakta kloner av moderplantan.",storageYears:"Ej tillämpligt",tip:"Rotskott är enklast och ger identiska kopior av moderplantan. Gräv upp dem på hösten och ge bort till odlarkompisar - aronia förtjänar att spridas!"},storage:{shelfLife:"2-4 veckor (färska i kylskåp)",methods:[{method:"Frysning",icon:"snowflake",duration:"12+ månader",description:"Bästa och enklaste metoden. Aroniabär fryser utmärkt och behåller alla nyttigheter. Frys direkt i påsar - bären klumpar inte ihop sig lika lätt som andra bär. Perfekt bas för juice och smoothies.",best:!0},{method:"Juice/must",icon:"storage",duration:"6-12 månader (pastöriserad)",description:"Aroniajuice är intensivt mörk och nyttig. Safta med ångsaftare eller koka och sila. Blanda gärna med äpple eller aronia-äpple 50/50 för bättre smak.",best:!1},{method:"Torkning",icon:"sun",duration:"12+ månader",description:"Torkade aroniabär blir söta, russsinlika och förlorar mycket av strävan. Torka i ugn på 50-60°C i 8-12 timmar. Fantastiska i müsli, bakning och som snacks.",best:!1},{method:"Sylt/marmelad",icon:"storage",duration:"1+ år",description:"Aroniasylt med lite citron har en djup, komplex smak. Koka med socker och citronjuice. Blanda gärna med äpple för bättre konsistens och smak.",best:!1},{method:"Kylskåp",icon:"snowflake",duration:"2-4 veckor",description:"Aroniabär har förvånansvärt lång hållbarhet färska. Fasta bär med högt tannininnehåll gör att de håller sig bättre än de flesta bär. Förvara torrt och svalt.",best:!1}],tips:["Skörda när bären är helt svarta och mjuka vid tryck - de mognar inte efter plockning","Hela klasar kan klippas av med sax - enklare och snabbare än att plocka bär för bär","Torkade aroniabär liknar russin och är mycket godare än färska","Aronia + äpple är den magiska kombinationen - oavsett om det är juice, sylt eller smoothie","Bären innehåller naturligt konserverande ämnen och håller sig längre än de flesta bär"]},harvestCalc:{minPerSqm:1,maxPerSqm:3,unit:"kg"},pruning:{label:"Beskärning",types:{maintenance:{name:"Underhållsbeskärning",when:"Tidig vår (feb-mars) innan knopparna svällt",description:"Aronia kräver minimal beskärning. Busken sköter sig i stort sett själv, men årlig gallring håller den produktiv och luftig. Aronia bär bäst på 2-5 år gamla grenar - ta bort de äldsta för att ge plats åt nya.",steps:["Ta bort döda, skadade och sjuka grenar","Ta bort grenar som är 5-6+ år gamla vid basen","Gallra svaga, korsande skott i mitten av busken","Spara 8-12 starka grenar i blandade åldrar","Klipp bort oönskade rotskott"]},rejuvenation:{name:"Föryngringsbeskärning",when:"Tidig vår",description:"Gammal, förvuxen aroniabuske? Hon tål hård beskärning utmärkt. Klipp ner till 20-30 cm och busken skjuter nya, friska skott från basen. Skörd igen om 2-3 år.",steps:["Klipp ner hela busken till 20-30 cm ovan mark","Nya skott dyker upp inom veckor","Välj ut 8-10 starka skott och ta bort resten","Gödsla med kompost och vattna ordentligt","Ny skörd från år 2-3"]}}},propagation:{difficulty:"Enkel",methods:[{method:"Rotskott",description:"Enklaste metoden. Aronia bildar naturligt rotskott runt busken. Gräv upp med rötter på hösten och plantera om direkt. Ger identiska kloner av moderplantan.",icon:"seedling"},{method:"Vedartade sticklingar",description:"Klipp 15-20 cm bitar av årets mogna skott i november. Sätt i fuktig jord utomhus. Rotar sig under vintern. Bra lyckandefrekvens.",icon:"scissors"},{method:"Delning",description:"Gräv upp en etablerad buske och dela med spade i 2-3 delar med rötter och skott. Plantera om direkt. Bäst på tidig vår eller sen höst.",icon:"scissors"}],tip:"Rotskott är enklast - aronia producerar dem gärna. Om du inte har en moderplanta att ta från, fungerar vedartade sticklingar i november utmärkt med hög lyckandefrekvens."}};export{r as aronia};
